class Solution:
    def crackSafe(self, n: int, k: int) -> str:
        if n == 1: return "".join(str(i) for i in range(k))
        seen = set()
        ans = []
        def dfs(node):
            for d in map(str, range(k)):
                edge = node + d
                if edge in seen: continue
                seen.add(edge)
                dfs(edge[1:])
                ans.append(d)
        start = "0" * (n-1)
        dfs(start)
        return start + "".join(ans)

